// ── Sanitize function for XSS prevention ──

function sanitize(str){
return String(str || '')
.replace(/[<>&"']/g, c => ({
'<':'&lt;',
'>':'&gt;',
'&':'&amp;',
'"':'&quot;',
"'":'&#x27;'
}[c]));
}

// ── Flag for preventing race conditions in getServices ──

let _isSyncing = false;
let _supabaseLoadWarningKey = '';
let _supabaseLastRemoteLoadFailed = false;

function warnSupabaseLoadOnce(key, message) {
  if (_supabaseLoadWarningKey === key) return;
  _supabaseLoadWarningKey = key;
  console.warn('[Supabase]', message);
  toast(`⚠️ ${message}`, 'warn');
}

function clearSupabaseLoadWarnings() {
  _supabaseLoadWarningKey = '';
  _supabaseLastRemoteLoadFailed = false;
}

// ── Normaliza nome: sem acento, minúsculo, sem espaços extras ──
function normalizarNome(nome) {
  if (!nome || typeof nome !== 'string') return '';
  return nome.trim()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ');
}

function normalizarTecnicosIds(ids) {
  return [...new Set(
    (Array.isArray(ids) ? ids : [])
      .map(id => String(id || '').trim())
      .filter(Boolean)
  )];
}

function extrairNomesEquipeLegada(equipeStr) {
  if (!equipeStr || !String(equipeStr).trim()) return [];
  return String(equipeStr)
    .split(/[\/,]+/)
    .map(nome => nome.trim())
    .filter(Boolean);
}

function getTecnicosMapById() {
  return new Map(
    (window._tecnicos || []).map(t => [String(t.id), { id: String(t.id), nome: String(t.nome || '').trim() }])
  );
}

function getTecnicosMapByNome() {
  const map = new Map();
  (window._tecnicos || []).forEach(t => {
    const nome = String(t?.nome || '').trim();
    const key = normalizarNome(nome);
    if (key && !map.has(key)) map.set(key, String(t.id));
  });
  return map;
}

function equipeLegadaParaTecnicosIds(equipeStr) {
  const byNome = getTecnicosMapByNome();
  return normalizarTecnicosIds(
    extrairNomesEquipeLegada(equipeStr)
      .map(nome => byNome.get(normalizarNome(nome)))
      .filter(Boolean)
  );
}

function getServiceTecnicosIds(servico) {
  if (!servico) return [];
  const diretos = normalizarTecnicosIds(servico.tecnicos_ids || servico.tecnicosIds || servico.technicians_ids);
  if (diretos.length) return diretos;
  return equipeLegadaParaTecnicosIds(servico.equipe || servico.eq || '');
}

function nomesTecnicos(ids){
  const lista = window._tecnicos || [];
  return normalizarTecnicosIds(ids).map(id => {
    const t = lista.find(x => String(x.id) === String(id));
    return t ? t.nome : '';
  }).filter(Boolean).join(' / ');
}

function getEquipeTexto(s){
if(s.tecnicos_ids && s.tecnicos_ids.length){
return nomesTecnicos(s.tecnicos_ids);
}

if(s.equipe){
return s.equipe;
}

return '—';
}

function getServiceTecnicos(servico) {
  const byId = getTecnicosMapById();
  const fromIds = getServiceTecnicosIds(servico).map(id => {
    const tecnico = byId.get(String(id));
    return tecnico ? { id: tecnico.id, nome: tecnico.nome } : null;
  }).filter(Boolean);

  if (fromIds.length) return fromIds;

  return extrairNomesEquipeLegada(servico?.equipe || servico?.eq || '').map(nome => ({
    id: `legacy:${normalizarNome(nome)}`,
    nome
  }));
}

function getServiceEquipeLabel(servico) {
  const nomes = nomesTecnicos(getServiceTecnicosIds(servico));
  return nomes || String(servico?.equipe || servico?.eq || '').trim();
}

function serviceTemEquipe(servico) {
  return !!getServiceEquipeLabel(servico);
}

function getServiceEquipeGroupKey(servico) {
  const ids = getServiceTecnicosIds(servico);
  if (ids.length) return `ids:${ids.join('|')}`;
  const legacy = String(servico?.equipe || servico?.eq || '').trim();
  return legacy ? `legacy:${normalizarNome(legacy)}` : 'sem-equipe';
}

function extrairTecnicos(servico) {
  if (servico && typeof servico === 'object' && !Array.isArray(servico)) {
    return getServiceTecnicos(servico).map(t => t.nome);
  }
  const ids = equipeLegadaParaTecnicosIds(servico);
  const nomes = nomesTecnicos(ids);
  return nomes ? nomes.split(' / ') : extrairNomesEquipeLegada(servico);
}

function getTecnicosUnicos(servicos){
  const set = new Set();
  (servicos||[]).forEach(s => {
    let ids = Array.isArray(s.tecnicos_ids) ? s.tecnicos_ids.slice() : [];
    if (!ids.length) {
      const equipes = String(s.equipe || s.eq || '').trim();
      if (equipes) ids = equipeLegadaParaTecnicosIds(equipes);
    }
    if (!ids.length) {
      ids = Array.isArray(getServiceTecnicosIds(s)) ? getServiceTecnicosIds(s) : [];
    }
    ids.forEach(id => { if (id !== undefined && id !== null && String(id).trim()) set.add(String(id)); });
  });
  return Array.from(set);
}

function calcularTempoServico(s){
if(!s.tipos) return 60;

return s.tipos.reduce((total, tipo) => {
return total + (CONFIG.tempos[tipo] || 60);
}, 0);
}

function calcularCapacidade(servicosHoje){

const tecnicos = getTecnicosUnicos(servicosHoje).length;

const total = tecnicos * JORNADA_MIN;

const usado = (servicosHoje||[]).reduce((acc, s) => acc + calcularTempoServico(s), 0);

return {
total,
usado,
livre: total - usado
};
}

function normalizarTecnicosIdsServicos() {
  if (!Array.isArray(services)) return false;
  let mudou = false;
  services = services.map(s => {
    const tecnicos_ids = getServiceTecnicosIds(s);
    const equipe = nomesTecnicos(tecnicos_ids) || String(s.equipe || s.eq || '').trim();
    const atuais = normalizarTecnicosIds(s.tecnicos_ids);
    const idsIguais = tecnicos_ids.join('|') === atuais.join('|');
    const equipeIgual = equipe === String(s.equipe || '').trim();
    if (idsIguais && equipeIgual) return s;
    mudou = true;
    return { ...s, tecnicos_ids, equipe };
  });
  if (mudou && typeof saveSvcs === 'function') saveSvcs();
  return mudou;
}

