// MOTOR DE TEMPO OPERACIONAL — v7.4
// Calcula tempo real consumido por serviço.
// Base de decisão para Dashboard e Painel Hoje.
// ════════════════════════════════════════════════

// ── Tabela de tempos por tipo × categoria ─────
// Unidade: minutos. Residencial = apartamento/casa.
// Condomínio = áreas comuns + múltiplos pontos.
const TEMPO_SERVICO = {
  DS_RES:   60,   // Desinsetização residencial
  DS_COND: 120,   // Desinsetização condomínio
  DR_RES:   60,   // Desratização residencial
  DR_COND: 120,   // Desratização condomínio
  DST:      90,   // Desentupimento (único tempo — varia pouco)
  DSC_RES:  90,   // Descupinização residencial
  DSC_COND:150,   // Descupinização condomínio
  LCA:     180,   // Limpeza de caixa d'água
  HIG:     240,   // Higienização de estofados
  MON:      45,   // Monitoramento / iscagem (inspeção rápida)
  TERMO:    60,   // Termo / laudo
  // ── Novos tipos operacionais ──────────────────────────────
  VIS:      30,   // Vistoria rápida
  REU:      60,   // Reunião
  VISTEC:   60,   // Visita técnica
  MAN:      45,   // Manobra
  OUTRO:    90,   // Tipo não mapeado → padrão
};

const TEMPO_DESLOCAMENTO = 20; // minutos entre serviços (fixo por serviço)
const JORNADA_MIN        = 588; // 08:00–17:48 = 588 min

const CONFIG = {
jornadaMin: JORNADA_MIN,
tempos: {
DS: 60,
DR: 60,
DST: 90,
LCA: 240
}
};

// ── Estimar distância entre dois endereços (km) ──
function estimateDistance(addr1, addr2) {
  const a1 = (addr1 || '').trim();
  const a2 = (addr2 || '').trim();
  if (!a1 || !a2) return 25;
  if (a1.toLowerCase() === a2.toLowerCase()) return 0; // mesmo endereço

  const neighborhoods = [
    'Centro','Liberdade','Bela Vista','Consolação','Higienópolis','Pacaembu','Perdizes',
    'Vila Madalena','Pinheiros','Vila Mariana','Moema','Itaim Bibi','Jardins','Brooklin',
    'Vila Olimpia','Santana','Tatuapé','Vila Prudente','Osasco','Barueri',
  ];
  const getNeighborhood = (addr) => {
    const lower = addr.toLowerCase();
    for (let n of neighborhoods) {
      if (lower.includes(n.toLowerCase())) return n;
    }
    return 'Outro';
  };

  const n1 = getNeighborhood(a1);
  const n2 = getNeighborhood(a2);
  if (n1 === n2 && n1 !== 'Outro') return 5;   // mesmo bairro
  if (n1 !== 'Outro' && n2 !== 'Outro') return 15; // bairros diferentes (SP)
  return 25; // um ou ambos fora do mapa
}

// ── Identificar se serviço é Condomínio ───────
// Palavras-chave no nome do cliente ou no campo tipoServico
function ehCondominio(servico) {
  const haystack = [
    servico.cliente || servico.cl || '',
    servico.endereco || '',
    servico.observacoes || servico.obs || '',
    servico.sc || '',
  ].join(' ').toLowerCase();
  return /cond|condom[ií]n|edif[íi]c|cond\./.test(haystack);
}

// ── Extrair lista de tipos de um serviço ──────
// Entrada:  "DS + DR", "DS/DR", "DS e DR", "DS", "LCA"
// Saída:    ["DS", "DR"] — sempre maiúsculos, sem duplicatas
function extrairTiposServico(servico) {
  const raw = [
    servico.tipoServico || '',
    servico.sc || '',
  ].join(' ');

  // Normalizar separadores → espaço, depois split por palavras-chave conhecidas
  const normalizado = raw
    .toUpperCase()
    .replace(/[+\/,&]/g, ' ')
    .replace(/E/g, ' ')      // "e" como conjunção
    .replace(/DE/g, ' ')
    .replace(/COM/g, ' ')
    .replace(/[^A-Z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  const TIPOS_VALIDOS = ['DS','DR','DST','DSC','LCA','HIG','MON','TERMO','ISCA','PC','VIS','REU','VISTEC','MAN'];
  const encontrados = [];
  const tokens = normalizado.split(' ');
  tokens.forEach(t => {
    if (TIPOS_VALIDOS.includes(t) && !encontrados.includes(t)) {
      encontrados.push(t);
    }
  });

  // Se nada identificado, tentar tipoServico direto
  if (encontrados.length === 0) {
    const ts = (servico.tipoServico || '').toUpperCase().split(/[\s/,+]/)[0];
    if (ts && ts.length > 0) encontrados.push(ts);
  }

  return encontrados.length > 0 ? encontrados : ['OUTRO'];
}

// ── Calcular tempo base de um tipo + categoria ─
function tempoParaTipo(tipo, isCond) {
  switch (tipo) {
    case 'DS':     return isCond ? TEMPO_SERVICO.DS_COND    : TEMPO_SERVICO.DS_RES;
    case 'DR':     return isCond ? TEMPO_SERVICO.DR_COND    : TEMPO_SERVICO.DR_RES;
    case 'DSC':    return isCond ? TEMPO_SERVICO.DSC_COND   : TEMPO_SERVICO.DSC_RES;
    case 'DST':    return TEMPO_SERVICO.DST;
    case 'LCA':    return TEMPO_SERVICO.LCA;
    case 'HIG':    return TEMPO_SERVICO.HIG;
    case 'MON':    return TEMPO_SERVICO.MON;
    case 'ISCA':   return TEMPO_SERVICO.MON;   // alias
    case 'TERMO':  return TEMPO_SERVICO.TERMO;
    case 'VIS':    return TEMPO_SERVICO.VIS;
    case 'REU':    return TEMPO_SERVICO.REU;
    case 'VISTEC': return TEMPO_SERVICO.VISTEC;
    case 'MAN':    return TEMPO_SERVICO.MAN;
    default:       return TEMPO_SERVICO.OUTRO;
  }
}
// ── Calcular tempo total de um único serviço (legado, sem efeito em capacidade v2) ──
// Considera: tipos (combo), categoria (res/cond), nº de técnicos
// Retorna minutos (tempo base + deslocamento), mínimo 30 min.
function calcularTempoServicoLegacy(servico) {
  const tipos   = extrairTiposServico(servico);
  const isCond  = ehCondominio(servico);

  // Soma dos tempos base de cada tipo do combo
  const tempoBase = tipos.reduce((acc, t) => acc + tempoParaTipo(t, isCond), 0);

  // Tempo total = base × técnicos + deslocamento
  // Nota: técnicos aumentam capacidade, não duplicam tempo;
  // aqui usamos como multiplicador de "tempo-homem" para refletir
  // o custo operacional real da alocação.
  const tempoTotal = tempoBase + TEMPO_DESLOCAMENTO;

  return Math.max(tempoTotal, 30); // mínimo 30 min por serviço
}

// ── Multiplicador de complexidade baseado em observações ──
function getComplexityMultiplier(servico) {
  const obs = (servico.observacoes || servico.obs || '').toLowerCase();
  if (obs.includes('complexo') || obs.includes('danos') || obs.includes('estrutural') || obs.includes('acesso difícil')) return 1.3;
  if (obs.includes('grande') || obs.includes('comercial')) return 1.2;
  if (obs.includes('simples') || obs.includes('rápido') || obs.includes('básico')) return 0.85;
  return 1.0;
}

// ── Tempo base do serviço (sem deslocamento) ──
function calcularTempoServicoBase(servico) {
  const tipos   = extrairTiposServico(servico);
  const isCond  = ehCondominio(servico);
  const tempoBase = tipos.reduce((acc, t) => acc + tempoParaTipo(t, isCond), 0);
  const multiplier = getComplexityMultiplier(servico);
  return Math.max(tempoBase * multiplier, 30);
}

// ── Tempo total consumido por um array de serviços ──
function calcularTempoTotalDia(servicos) {
  if (!servicos.length) return 0;

  // Sort by horario
  const sorted = [...servicos].sort((a, b) => {
    const h1 = a.horario || a.hr || '00:00';
    const h2 = b.horario || b.hr || '00:00';
    return h1.localeCompare(h2);
  });

  let totalServiceTime = 0;
  let totalRouteTime = 0;

  for (let i = 0; i < sorted.length; i++) {
    totalServiceTime += calcularTempoServicoBase(sorted[i]);
    if (i > 0) {
      const dist = estimateDistance(sorted[i-1].endereco || '', sorted[i].endereco || '');
      const displacement = dist * 2 + 5;
      totalRouteTime += displacement;
    }
  }

  return totalServiceTime + totalRouteTime;
}

// ── Capacidade real do dia ────────────────────
// Retorna objeto com métricas de tempo em minutos e percentuais
function calcularCapacidadeDia(servicos) {
  const tecnicos       = getTecnicosUnicos(servicos);
  const nTecnicos      = Math.max(tecnicos.length, 1);
  const tempoDisponivel= nTecnicos * JORNADA_MIN;          // minutos disponíveis no total
  const tempoConsumido = calcularTempoTotalDia(servicos);   // minutos consumidos
  const tempoLivre     = Math.max(0, tempoDisponivel - tempoConsumido);
  const pctOcup        = tempoDisponivel > 0 ? Math.round(tempoConsumido / tempoDisponivel * 100) : 0;
  // Slots estimados = tempo livre ÷ tempo médio por serviço genérico (110 min)
  const tempoMedioSvc  = TEMPO_SERVICO.OUTRO + TEMPO_DESLOCAMENTO; // 90+20 = 110
  const slotsLivres    = Math.floor(tempoLivre / tempoMedioSvc);
  const statusCap      = pctOcup >= 90 ? 'sobrecarregado' : pctOcup < 50 ? 'ocioso' : 'ok';

  return {
    nTecnicos,
    tempoDisponivel,  // min
    tempoConsumido,   // min
    tempoLivre,       // min
    pctOcup,          // 0-100
    slotsLivres,
    statusCap,
    // Formato legível
    hDisponivel: `${Math.floor(tempoDisponivel/60)}h${tempoDisponivel%60?tempoDisponivel%60+'min':''}`,
    hConsumido:  `${Math.floor(tempoConsumido/60)}h${tempoConsumido%60?String(tempoConsumido%60).padStart(2,'0')+'min':''}`,
    hLivre:      `${Math.floor(tempoLivre/60)}h${tempoLivre%60?String(tempoLivre%60).padStart(2,'0')+'min':''}`,
  };
}

